using Fixar.Domain.Entities;using Fixar.Infrastructure.Persistence;using Microsoft.EntityFrameworkCore;namespace Fixar.API.Controllers;internal static class SupplierFinanceSupport{public static string Status(SupplierPayable x)=>x.IsCancelled?"Cancelled":x.OutstandingAmount<=0?"Paid":x.DueDate.Date<DateTime.UtcNow.Date?"Overdue":x.AllocatedAmount>0?"PartiallyPaid":"Open";public static async Task<string>Next(ApplicationDbContext db,string kind,DateTime date,CancellationToken ct){await db.Database.ExecuteSqlRawAsync(kind=="PAY"?"SELECT pg_advisory_xact_lock(81320)":kind=="SPY"?"SELECT pg_advisory_xact_lock(81321)":kind=="SLE"?"SELECT pg_advisory_xact_lock(81322)":"SELECT pg_advisory_xact_lock(81323)",ct);var p=kind is "PAY" or "SPY"?$"{kind}-{date:yyyyMMdd}-":kind=="END"?$"END-{date:yyyyMMdd}-":$"SLE-{date:yyyyMMdd}-";var vals=kind switch{"PAY"=>await db.SupplierPayables.Where(x=>x.PayableNumber.StartsWith(p)).Select(x=>x.PayableNumber).ToListAsync(ct),"SPY"=>await db.SupplierPayments.Where(x=>x.PaymentNumber.StartsWith(p)).Select(x=>x.PaymentNumber).ToListAsync(ct),"END"=>await db.ChequeEndorsements.Where(x=>x.EndorsementNumber.StartsWith(p)).Select(x=>x.EndorsementNumber).ToListAsync(ct),_=>await db.SupplierLedgerEntries.Where(x=>x.EntryNumber.StartsWith(p)).Select(x=>x.EntryNumber).ToListAsync(ct)};var n=vals.Select(x=>int.TryParse(x[p.Length..],out var i)?i:0).DefaultIfEmpty().Max()+1;return$"{p}{n:0000}";}}
